var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"이면세계가 아닌 장소에서 임무는 처음이네.","JPN":"裏世界じゃない場所での任務は初めてだね。","ENG":"It's my first time being on a mission not in the Counterside.","TWN":"我還是第一次在異界以外的地方執行任務。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"드디어 사람들이 사는 마을에서 일하게 되는구나…","JPN":"やっと人が住んでる村で働くことになったんだ……","ENG":"I finally get to work in a village where actual people live...","TWN":"終於要在有人居住的村莊裡工作嗎…"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"좋아. 열심히 해야지!","JPN":"よし。頑張るぞ！","ENG":"Okay! I should work even harder!","TWN":"好，我要努力！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"여기가 정말 마을이 맞는 건가…?","JPN":"ここって、本当に村なのかな……？","ENG":"Is this really a village...?","TWN":"這裡真的就是村莊嗎…？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"너무 처참해. 분명 침식현상이 발생한 걸 거야.","JPN":"あまりにもひどい。きっと侵食現象が発生したんだ。","ENG":"It's devastating. There's no doubt that a Counterside Effect happened here.","TWN":"太慘了，肯定是發生了侵蝕現象。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"생존자는 어디 있지?","JPN":"生存者はどこ？","ENG":"But where are the survivors?","TWN":"倖存者在哪裡？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"UNKNOWN_DOLL_NPC_NULL","text":{"KOREA":"으, 으아아악!","JPN":"う、うわああっ！","ENG":"A-aargh!!","TWN":"呃，呃啊啊！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"UNKNOWN_DOLL_NPC_NULL","text":{"KOREA":"마, 마브카…! 마브카가 또 나타났어!","JPN":"マ、マブカ……！　またマブカが現われた！","ENG":"I-It's Mavka...! She's back!","TWN":"瑪、瑪卡…！瑪卡又出現了！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"모두 진정해 얘들아! 내가 구해줄게!","JPN":"みんな、落ち着いて！　私が助けてあげる！","ENG":"Calm down, everyone! I'll save you!","TWN":"大家冷靜點！我會救你們的！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHILD_DOLL_NPC_NULL","text":{"KOREA":"가, 가까이 오지 마…! 이 괴물!","JPN":"ち、近づかないで……！　この化け物！","ENG":"S-stay back...! You monster!","TWN":"別，別過來…！你這個怪物！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"괴물이라고? 어째서…?","JPN":"化け物？　どうして……？","ENG":"Monster...? But why...?","TWN":"怪物？為什麼…？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHILD_DOLL_NPC_NULL","text":{"KOREA":"죽여! 죽여버려!","JPN":"死ね！　死んじゃえ！","ENG":"Die! DIE!!","TWN":"殺了她！殺了她！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"지, 진정해 얘들아! 난 너희들을 구하러 온 거라고!","JPN":"み、みんな落ち着いて！　私があなたたちを助けに来たんだよ！","ENG":"C-calm down! I'm here to save you!","TWN":"冷，冷靜點！我是來救你們的！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"UNKNOWN_DOLL_NPC_NULL","text":{"KOREA":"<color=#ff3636>구하러 왔다고…? 정말 그렇게 생각해?</color>","JPN":"<color=#ff3636>助けに来た……？　本当にそう思う？</color>","ENG":"<color=#ff3636>You're here to save them...? Do you really think so?</color>","TWN":"<color=#ff3636>來救我們…？你真的這麼認為嗎？</color>"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"누구냐!","JPN":"誰だ！","ENG":"Who’s that?!","TWN":"是誰？！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"UNKNOWN_DOLL_NPC_NULL","text":{"KOREA":"<color=#ff3636>학살인형</color>께서 모두를 구하러 왔다니…","JPN":"<color=#ff3636>虐殺人形</color>がみんなを助けに来たって……","ENG":"The <color=#ff3636>Massacre Doll</color> is here to save everyone...","TWN":"<color=#ff3636>殺戮娃娃</color>竟然要來救我們……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"UNKNOWN_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"UNKNOWN_DOLL_NPC_NULL","text":{"KOREA":"왜 다시 찾아온거야? 설마 한 명도 남기지 말라는 명령을 받은 거니?","JPN":"どうしてまた来たの？　まさか、一人も生かしておくなと命令されたわけ？","ENG":"Why did you come back? Were you ordered to not leave a single person alive?","TWN":"你為什麼又來這裡？是接到命令要把我們全部殺光嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"UNKNOWN_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"저건…!","JPN":"あれは……！","ENG":"That's...!","TWN":"那是……！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"책에서 본 적 있어. 분명 그림자가 분명해….","JPN":"本で見たことある。確かシャドウのはず……","ENG":"I read it in a book. It's a Shadow...","TWN":"我在書上見過，那肯定是暗影。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"어째서 이런 곳에…?","JPN":"どうしてこんなところに……？","ENG":"Why is she even here...?","TWN":"為什麼會出現在這種地方……？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SHADOW_DOLL_NPC_NULL","text":{"KOREA":"무슨 소리야? 난 네가 처음 이면세계에 갔을 때부터 항상 곁에 있었는데…","JPN":"何を言っているの？　私はあなたが初めて裏世界に行った時からずっとそばにいたのに……","ENG":"What are you talking about? I've been with you ever since you first went to the Counterside...","TWN":"你在說什麼？我從你第一次去異界的時候就一直在你身邊…"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SHADOW_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SHADOW_DOLL_NPC_NULL","text":{"KOREA":"그 <color=#ffd34c>관속</color>에서 잘 지내는 것 같아 다행이야.","JPN":"その<color=#ffd34c>棺の中</color>で元気にしているようで、よかったわ。","ENG":"I'm relieved to see that you're doing well inside that <color=#ffd34c>coffin</color>.","TWN":"你在這副<color=#ffd34c>棺材</color>裡過得不錯，我很高興。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SHADOW_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SHADOW_DOLL_NPC_NULL","text":{"KOREA":"그 목소리… 확실해.","JPN":"その声……きっとそうだ。","ENG":"That voice... I know it.","TWN":"那個聲音……我認得你。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SHADOW_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHADOW_DOLL_NPC_NULL","text":{"KOREA":"■■. 아직도 날 못 알아보겠어?","JPN":"■■。まだ私のことがわからないの？","ENG":"■■. Can't you recognize me?","TWN":"■■，還不認得我嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SHADOW_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"난 너 같은 거 본 적 없어! 네가 아이들을 이렇게 만든 거냐!","JPN":"私はあなたなんて見たことない！　子どもたちをそそのかしたのはあなたね！？","ENG":"I've never seen you in my life! Are you the one who made the kids like this?!","TWN":"我從沒見過你這樣的人！是你把孩子們變成這樣的？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};